#!/usr/bin/env node
// AutoSEO fix script — generated by autoseo.live for the page audited.
// Zero dependencies (Node 18+ stdlib only). Idempotent: re-running over an
// already-fixed file is a no-op, not duplicated tags.
//
// Usage:
//   node autoseo-fix.mjs path/to/your/index.html
//   node autoseo-fix.mjs path/to/your/index.html --dry-run
//   node autoseo-fix.mjs path/to/your/index.html --no-backup
//
// Always writes <file>.bak before overwriting unless --no-backup.

import fs from "node:fs/promises";
import path from "node:path";

// Inlined at generation time by autoseo-app/src/generator.js.
const PAYLOAD = /*__AUTOSEO_PAYLOAD__*/ null;

const FIXES = PAYLOAD?.fixes || [];
const SOURCE_URL = PAYLOAD?.url || "(unknown)";
const GENERATED_AT = PAYLOAD?.generatedAt || "";

// ----- escapers ------------------------------------------------------------
function escapeHtml(s) {
  return String(s).replace(/[&<>"]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" }[c]));
}
function escapeAttr(s) {
  return String(s).replace(/&/g, "&amp;").replace(/"/g, "&quot;");
}

// ----- shared insert into <head> -------------------------------------------
function insertBeforeHead(html, block) {
  if (/<\/head>/i.test(html)) return html.replace(/<\/head>/i, `  ${block}\n</head>`);
  if (/<html[^>]*>/i.test(html)) return html.replace(/(<html[^>]*>)/i, `$1\n<head>\n${block}\n</head>`);
  return block + "\n" + html;
}

// ----- per-fix-type appliers (idempotent) ----------------------------------
function applyTitle(html, value) {
  const m = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  if (m) {
    if (m[1].trim() === value.trim()) return { html, applied: false, reason: "title already matches" };
    return {
      html: html.replace(/<title[^>]*>[\s\S]*?<\/title>/i, `<title>${escapeHtml(value)}</title>`),
      applied: true, before: m[1].trim(), after: value,
    };
  }
  return { html: insertBeforeHead(html, `<title>${escapeHtml(value)}</title>`), applied: true, after: value };
}

function applyDescription(html, value) {
  const re = /<meta\s+name=["']description["'][^>]*>/i;
  const m = html.match(re);
  if (m) {
    const cur = (m[0].match(/content=(?:"([^"]*)"|'([^']*)')/i) || [])[1] || "";
    if (cur === value) return { html, applied: false, reason: "description already matches" };
    return {
      html: html.replace(re, `<meta name="description" content="${escapeAttr(value)}" />`),
      applied: true, before: cur, after: value,
    };
  }
  return {
    html: insertBeforeHead(html, `<meta name="description" content="${escapeAttr(value)}" />`),
    applied: true, after: value,
  };
}

function applySchema(html, value) {
  if (/<script[^>]+type=["']application\/ld\+json["']/i.test(html)) {
    return { html, applied: false, reason: "JSON-LD already present (left untouched)" };
  }
  const v = value.trim();
  const block = /^<script/i.test(v) ? v : `<script type="application/ld+json">\n${v}\n</script>`;
  return { html: insertBeforeHead(html, block), applied: true, after: "JSON-LD inserted" };
}

function applyOg(html, value) {
  if (/<meta\s+property=["']og:title["']/i.test(html)) {
    return { html, applied: false, reason: "Open Graph tags already present" };
  }
  const lines = value.split(/\r?\n/).map((l) => l.trim()).filter((l) => /^<meta/i.test(l));
  if (!lines.length) return { html, applied: false, reason: "no <meta> lines in OG payload" };
  return { html: insertBeforeHead(html, lines.join("\n  ")), applied: true, after: `${lines.length} OG tag(s) inserted` };
}

function applyTldr(html, value) {
  if (/data-autoseo=["']tldr["']/i.test(html)) {
    return { html, applied: false, reason: "TL;DR already present" };
  }
  const body = value.replace(/^\s*TL;DR:?\s*/i, "").trim();
  const p = `<p data-autoseo="tldr"><b>In short:</b> ${escapeHtml(body)}</p>`;
  if (/<h1[^>]*>[\s\S]*?<\/h1>/i.test(html)) {
    return { html: html.replace(/(<h1[^>]*>[\s\S]*?<\/h1>)/i, `$1\n${p}`), applied: true, after: "after first <h1>" };
  }
  if (/<body[^>]*>/i.test(html)) {
    return { html: html.replace(/(<body[^>]*>)/i, `$1\n${p}`), applied: true, after: "at start of <body>" };
  }
  return { html, applied: false, reason: "no <body> or <h1> to anchor TL;DR" };
}

const HANDLERS = { title: applyTitle, description: applyDescription, schema: applySchema, og: applyOg, tldr: applyTldr };

// ----- CLI ----------------------------------------------------------------
function usage() {
  console.log("Usage: node autoseo-fix.mjs <file.html> [--dry-run] [--no-backup]");
}

async function main() {
  const argv = process.argv.slice(2);
  const flags = { dryRun: false, backup: true };
  let file = null;
  for (const a of argv) {
    if (a === "--dry-run") flags.dryRun = true;
    else if (a === "--no-backup") flags.backup = false;
    else if (a === "-h" || a === "--help") { usage(); process.exit(0); }
    else if (!a.startsWith("-") && !file) file = a;
    else { console.error(`Unknown argument: ${a}`); usage(); process.exit(2); }
  }
  if (!file) { usage(); process.exit(2); }
  if (!FIXES.length) { console.log("This script has no fixes embedded — nothing to apply."); return; }

  const abs = path.resolve(file);
  let html;
  try { html = await fs.readFile(abs, "utf8"); }
  catch (e) { console.error(`Cannot read ${abs}: ${e.message}`); process.exit(1); }

  console.log(`\n  AutoSEO fix script`);
  console.log(`  Source URL : ${SOURCE_URL}`);
  if (GENERATED_AT) console.log(`  Generated  : ${GENERATED_AT}`);
  console.log(`  Target file: ${abs}`);
  console.log(`  Fixes      : ${FIXES.length}\n`);

  let out = html;
  const applied = [];
  const skipped = [];
  for (const fx of FIXES) {
    const fn = HANDLERS[fx.type];
    if (!fn) { skipped.push({ type: fx.type, reason: "unknown fix type" }); console.log(`    - ${fx.type}  (unknown type)`); continue; }
    const r = fn(out, fx.value || "");
    if (r.applied) { out = r.html; applied.push({ type: fx.type, before: r.before, after: r.after }); console.log(`    + ${fx.type}`); }
    else { skipped.push({ type: fx.type, reason: r.reason }); console.log(`    - ${fx.type}  (${r.reason})`); }
  }

  if (flags.dryRun) { console.log("\n  --dry-run — no files written.\n"); return; }
  if (!applied.length) { console.log("\n  Nothing to change — file already up to date.\n"); return; }
  if (flags.backup) {
    await fs.writeFile(abs + ".bak", html, "utf8");
    console.log(`\n  Backup → ${abs}.bak`);
  }
  await fs.writeFile(abs, out, "utf8");
  console.log(`  Wrote  → ${abs}`);
  console.log(`\n  ${applied.length} applied, ${skipped.length} skipped. Review and commit/deploy as usual.\n`);
}

main().catch((e) => { console.error(`fix script failed: ${e.message}`); process.exit(1); });
